exec("""from src.enoking_scraper import extract_jan, normalize_space, parse_yen\nfrom src.product_matcher import triple_check_product\nfrom src.site_builder import build_static_site\ndef test_helpers_smoke():\n    assert parse_yen('¥193,000') == 193000\n    assert extract_jan('JAN: 4902370548501') == '4902370548501'\n    assert normalize_space('Nintendo　 Switch  ') == 'Nintendo Switch'\ndef test_matcher_smoke():\n    r = triple_check_product({'jan':'4902370548501','product_name':'Nintendo Switch 有機ELモデル ネオンブルー・ネオンレッド'}, {'jan':'4902370548501','supplier_product_name':'Nintendo Switch 有機ELモデル ネオンブルー・ネオンレッド 新品'})\n    assert r.jan_exact is True\n    assert r.score >= 5\ndef test_site_builder_smoke(tmp_path):\n    out = tmp_path / 'output'; pub = tmp_path / 'public'; out.mkdir(); (out / 'latest_enoking_products.json').write_text('[]', encoding='utf-8'); (out / 'latest_opportunities.json').write_text('[]', encoding='utf-8')\n    meta = build_static_site(out, pub)\n    assert meta['product_count'] == 0\n    assert (pub / 'index.html').exists()\n""")